// Formatting utilities for session metrics display

import dayjs from 'dayjs'
import relativeTime from 'dayjs/plugin/relativeTime'

dayjs.extend(relativeTime)

export const formatMs = (ms: number): string => {
  if (ms < 1) return '<1ms'
  if (ms < 1000) return `${Math.round(ms)}ms`
  return `${(ms / 1000).toFixed(2)}s`
}

export const formatDuration = (ms: number | null): string => {
  if (ms == null) return '—'
  const seconds = Math.floor(ms / 1000)
  const minutes = Math.floor(seconds / 60)
  const hours = Math.floor(minutes / 60)
  if (hours > 0) return `${hours}h ${minutes % 60}m ${seconds % 60}s`
  if (minutes > 0) return `${minutes}m ${seconds % 60}s`
  return `${seconds}s`
}

export const formatDate = (iso: string | null): string => {
  if (!iso) return '—'
  return dayjs(iso).format('MMM D, YYYY h:mm A')
}

export const computeAvg = (values: number[]) => {
  if (!values.length) return 0
  return Math.round(values.reduce((a, b) => a + b, 0) / values.length)
}

export const computePercentile = (values: number[], p: number) => {
  if (!values.length) return 0
  const sorted = [...values].sort((a, b) => a - b)
  const idx = Math.min(Math.floor(sorted.length * p), sorted.length - 1)
  return sorted[idx]
}

import type { AgentSessionRow, PlivoListResponse } from '@/lib/observability-types'

export function createObservabilityApi(baseUrl: string) {
  async function fetchJson<T>(path: string): Promise<T> {
    const res = await fetch(`${baseUrl}${path}`)
    if (!res.ok) throw new Error(`API error: ${res.status} ${res.statusText}`)
    return res.json()
  }

  return {
    listSessions: (limit = 20, offset = 0, accountId?: string) => {
      const params = new URLSearchParams({ limit: String(limit), offset: String(offset) })
      if (accountId) params.set('account_id', accountId)
      return fetchJson<PlivoListResponse<AgentSessionRow>>(`/sessions?${params}`)
    },

    getSession: (id: string) =>
      fetchJson<AgentSessionRow>(`/sessions/${id}`),
  }
}

export type ObservabilityApi = ReturnType<typeof createObservabilityApi>

import {
  createContext,
  useContext,
  useEffect,
  useMemo,
  useState,
  type ReactNode,
} from 'react'
import { createObservabilityApi, type ObservabilityApi } from '@/lib/observability-api'
import type { AgentSessionRow } from '@/lib/observability-types'

interface ObservabilityContextValue {
  api: ObservabilityApi
  session: AgentSessionRow | null
  sessionLoading: boolean
  sessionError: string | null
  highlightedTurn: number | null
  setHighlightedTurn: (turn: number | null) => void
}

const ObservabilityContext = createContext<ObservabilityContextValue | null>(null)

export function AgentObservabilityProvider({
  baseUrl,
  sessionId,
  children,
}: {
  baseUrl: string
  sessionId?: string
  children: ReactNode
}) {
  const api = useMemo(() => createObservabilityApi(baseUrl), [baseUrl])
  const [session, setSession] = useState<AgentSessionRow | null>(null)
  const [sessionLoading, setSessionLoading] = useState(!!sessionId)
  const [sessionError, setSessionError] = useState<string | null>(null)
  const [highlightedTurn, setHighlightedTurn] = useState<number | null>(null)

  useEffect(() => {
    if (!sessionId) {
      setSession(null)
      setSessionLoading(false)
      return
    }
    setSessionLoading(true)
    setSessionError(null)
    api
      .getSession(sessionId)
      .then(setSession)
      .catch((e) => setSessionError(e.message))
      .finally(() => setSessionLoading(false))
  }, [api, sessionId])

  const value = useMemo<ObservabilityContextValue>(
    () => ({
      api,
      session,
      sessionLoading,
      sessionError,
      highlightedTurn,
      setHighlightedTurn,
    }),
    [api, session, sessionLoading, sessionError, highlightedTurn],
  )

  return (
    <ObservabilityContext.Provider value={value}>
      {children}
    </ObservabilityContext.Provider>
  )
}

export function useObservabilityContext() {
  const ctx = useContext(ObservabilityContext)
  if (!ctx) {
    throw new Error('useObservabilityContext must be used within AgentObservabilityProvider')
  }
  return ctx
}

import { useEffect, useMemo, useState } from 'react'
import { useObservabilityContext } from '@/lib/observability-provider'
import type {
  AgentSessionRow,
  ChatItem,
  MetricsSummary,
  PlivoMeta,
  SessionEvent,
  SessionMetrics,
  TurnRecord,
} from '@/lib/observability-types'

// ---------------------------------------------------------------------------
// useSessions — fetches paginated session list
// ---------------------------------------------------------------------------

export function useSessions(
  limit = 20,
  initialOffset = 0,
  accountId?: string,
) {
  const { api } = useObservabilityContext()
  const [sessions, setSessions] = useState<AgentSessionRow[]>([])
  const [meta, setMeta] = useState<PlivoMeta>({
    limit,
    offset: initialOffset,
    total_count: 0,
    next: null,
    previous: null,
  })
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [offset, setOffset] = useState(initialOffset)

  useEffect(() => {
    setLoading(true)
    setError(null)
    api
      .listSessions(limit, offset, accountId)
      .then((res) => {
        setSessions(res.objects)
        setMeta(res.meta)
      })
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false))
  }, [api, limit, offset, accountId])

  return { sessions, meta, loading, error, offset, setOffset }
}

// ---------------------------------------------------------------------------
// useSession — returns the current session from provider context
// ---------------------------------------------------------------------------

export function useSession() {
  const { session, sessionLoading, sessionError } = useObservabilityContext()
  return {
    session,
    loading: sessionLoading,
    error: sessionError,
  }
}

// ---------------------------------------------------------------------------
// useTimeline — derives timeline data from current session
// ---------------------------------------------------------------------------

export function useTimeline() {
  const { session, highlightedTurn, setHighlightedTurn } =
    useObservabilityContext()

  const metrics: SessionMetrics | null = session?.session_metrics ?? null
  const recordUrl: string | null = session?.record_url ?? null
  const sessionCreatedAt: string | undefined = session?.created_at

  return { metrics, recordUrl, sessionCreatedAt, highlightedTurn, setHighlightedTurn }
}

// ---------------------------------------------------------------------------
// useTranscript — derives transcript data from current session
// ---------------------------------------------------------------------------

export function useTranscript() {
  const { session, highlightedTurn, setHighlightedTurn } =
    useObservabilityContext()

  const metrics: SessionMetrics | null = session?.session_metrics ?? null
  const turns: TurnRecord[] = useMemo(
    () => metrics?.turns ?? [],
    [metrics],
  )
  const chatHistory: ChatItem[] | null = session?.chat_history ?? null

  return { turns, chatHistory, metrics, highlightedTurn, setHighlightedTurn }
}

// ---------------------------------------------------------------------------
// usePerformance — derives performance metrics from current session
// ---------------------------------------------------------------------------

export function usePerformance() {
  const { session } = useObservabilityContext()

  const metrics: SessionMetrics | null = session?.session_metrics ?? null
  const summary: MetricsSummary | null = metrics?.summary ?? null

  return { metrics, summary }
}

// ---------------------------------------------------------------------------
// useEvents / useOptions — raw session report slices
// ---------------------------------------------------------------------------

export function useEvents(): SessionEvent[] | null {
  const { session } = useObservabilityContext()
  return session?.events ?? null
}

export function useOptions(): Record<string, unknown> | null {
  const { session } = useObservabilityContext()
  return session?.options ?? null
}

import { Fragment } from 'react'
import { ResponsiveContainer } from 'recharts'

interface TooltipRow {
  label: string
  value: string
  color?: string
}

export const ChartTooltipShell = ({
  active,
  label,
  rows,
}: {
  active?: boolean
  label?: string | number
  rows: TooltipRow[]
}) => {
  if (!active || !rows.length) return null
  return (
    <div className="rounded-lg border bg-background p-3 text-s-400 shadow-md">
      <p className="font-medium mb-1">Turn {label}</p>
      <div className="grid grid-cols-2 gap-x-4 gap-y-0.5">
        {rows.map((r) => (
          <Fragment key={r.label}>
            <span
              className="text-muted-foreground"
              style={r.color ? { color: r.color } : undefined}
            >
              {r.label}
            </span>
            <span>{r.value}</span>
          </Fragment>
        ))}
      </div>
    </div>
  )
}

export const ChartLegendItem = ({ color, label }: { color: string; label: string }) => {
  return (
    <span className="flex items-center gap-1.5">
      <span className="inline-block h-2.5 w-2.5 rounded-sm" style={{ background: color }} />
      {label}
    </span>
  )
}

interface LegendEntry {
  color: string
  label: string
}

export const ChartCard = ({
  title,
  subtitle,
  legend,
  chartHeight = 'h-64',
  children,
}: {
  title: string
  subtitle?: string
  legend: LegendEntry[]
  chartHeight?: string
  children: React.ReactNode
}) => {
  return (
    <div className="rounded-lg border p-5">
      <span className="text-p-400 font-medium">{title}</span>
      {subtitle && <p className="text-xs text-muted-foreground mt-0.5">{subtitle}</p>}
      <div className={`mt-3 ${chartHeight}`}>
        <ResponsiveContainer width="100%" height="100%">
          {children as React.ReactElement}
        </ResponsiveContainer>
      </div>
      {legend.length > 0 && (
        <div className="mt-2 flex items-center gap-4 text-xs text-muted-foreground">
          {legend.map((l) => (
            <ChartLegendItem key={l.label} color={l.color} label={l.label} />
          ))}
        </div>
      )}
    </div>
  )
}

import { Clock, Coins, Gauge, MessageCircle, Wrench, Zap } from 'lucide-react'
import { formatMs } from '@/lib/observability-format'
import type { SessionMetrics } from '@/lib/observability-types'
import { usePerformance } from '@/lib/observability-hooks'

const LATENCY_COLOR: Record<string, string> = {
  success: 'text-green-600',
  warning: 'text-amber-600',
  destructive: 'text-destructive',
}

const p95Color = (ms: number) => {
  if (ms < 500) return LATENCY_COLOR.success
  if (ms < 1000) return LATENCY_COLOR.warning
  return LATENCY_COLOR.destructive
}

const StatCard = ({
  icon: Icon,
  label,
  value,
  sub,
  valueColor,
}: {
  icon: React.ElementType
  label: string
  value: string
  sub?: string
  valueColor?: string
}) => {
  return (
    <div className="group rounded-lg border bg-card p-4 transition-colors hover:border-primary/20">
      <div className="flex items-center gap-2 mb-2">
        <div className="flex h-6 w-6 items-center justify-center rounded-md bg-muted">
          <Icon size={13} className="text-primary" />
        </div>
        <span className="text-xs text-muted-foreground">{label}</span>
      </div>
      <span className={`text-h1-400 font-semibold tracking-tight ${valueColor || ''}`}>{value}</span>
      {sub && <p className="text-[10px] text-muted-foreground mt-1">{sub}</p>}
    </div>
  )
}

export const MetricSummaryCards = ({ metrics: metricsProp }: { metrics?: SessionMetrics | null }) => {
  const { metrics: hookMetrics } = usePerformance()
  const metrics = metricsProp ?? hookMetrics

  if (!metrics) return null

  const { summary } = metrics
  const p95 = summary.p95_user_perceived_ms ?? summary.latency?.user_perceived_ms?.p95 ?? null
  const avgLatency = summary.avg_user_perceived_ms ?? summary.latency?.user_perceived_ms?.avg ?? null
  const totalTokens = summary.total_llm_tokens ?? summary.usage?.total_llm_tokens ?? 0
  const interruptions = summary.interruptions ?? summary.interruption?.total_interruptions ?? 0

  return (
    <div className="grid grid-cols-2 gap-3 md:grid-cols-3 lg:grid-cols-6">
      <StatCard
        icon={MessageCircle}
        label="Turns"
        value={String(summary.total_turns)}
      />
      <StatCard
        icon={Zap}
        label="Interruptions"
        value={String(interruptions)}
      />
      <StatCard
        icon={Wrench}
        label="Tool Calls"
        value={String(summary.total_tool_calls)}
      />
      <StatCard
        icon={Gauge}
        label="P95 Latency"
        value={p95 != null ? formatMs(p95) : '—'}
        valueColor={p95 != null ? p95Color(p95) : undefined}
        sub={p95 != null ? 'user perceived' : undefined}
      />
      <StatCard
        icon={Clock}
        label="Avg Latency"
        value={avgLatency != null ? formatMs(avgLatency) : '—'}
        sub={avgLatency != null ? 'user perceived' : undefined}
      />
      <StatCard
        icon={Coins}
        label="Total Tokens"
        value={totalTokens > 0 ? totalTokens.toLocaleString() : '—'}
        sub={
          totalTokens > 0 && summary.total_turns > 0
            ? `~${Math.round(totalTokens / summary.total_turns).toLocaleString()}/turn`
            : undefined
        }
      />
    </div>
  )
}

import { useMemo } from 'react'
import { Bar, BarChart, CartesianGrid, Tooltip, XAxis, YAxis } from 'recharts'
import { computeAvg, computePercentile, formatMs } from '@/lib/observability-format'
import type { SessionMetrics, TurnRecord } from '@/lib/observability-types'
import { usePerformance } from '@/lib/observability-hooks'
import { ChartCard } from '@/components/observability-chart-shared'

interface ChartEntry {
  name: string
  avg: number
  p95: number
}

const PercentilesTooltip = ({
  active,
  payload,
}: {
  active?: boolean
  payload?: Array<{ payload: ChartEntry }>
}) => {
  if (!active || !payload?.length) return null
  const d = payload[0].payload
  return (
    <div className="rounded-lg border bg-background p-3 text-s-400 shadow-md">
      <p className="font-medium mb-1">{d.name}</p>
      <div className="grid grid-cols-2 gap-x-4 gap-y-0.5">
        <span className="text-muted-foreground">Avg</span>
        <span>{formatMs(d.avg)}</span>
        <span className="text-muted-foreground">P95</span>
        <span>{formatMs(d.p95)}</span>
      </div>
    </div>
  )
}

const METRIC_KEYS: { key: keyof TurnRecord; label: string }[] = [
  { key: 'user_perceived_ms', label: 'User Perceived' },
  { key: 'stt_delay_ms', label: 'STT Delay' },
  { key: 'llm_ttft_ms', label: 'LLM TTFT' },
  { key: 'tts_ttfb_ms', label: 'TTS TTFB' },
  { key: 'turn_decision_ms', label: 'Turn Decision' },
]

export const LatencyPercentilesChart = ({ metrics: metricsProp }: { metrics?: SessionMetrics | null }) => {
  const { metrics: hookMetrics } = usePerformance()
  const metrics = metricsProp ?? hookMetrics

  const chartData = useMemo(() => {
    if (!metrics?.turns?.length) return []

    return METRIC_KEYS.map((m) => {
      const values = metrics.turns
        .map((t) => t[m.key] as number | undefined)
        .filter((v): v is number => v != null)
      if (!values.length) return null
      return {
        name: m.label,
        avg: computeAvg(values),
        p95: computePercentile(values, 0.95),
      }
    }).filter((d): d is ChartEntry => d != null)
  }, [metrics])

  if (!chartData.length) return null

  return (
    <ChartCard
      title="Latency Percentiles"
      legend={[
        { color: 'hsl(var(--primary) / 0.4)', label: 'Avg' },
        { color: 'hsl(var(--primary))', label: 'P95' },
      ]}
    >
      <BarChart data={chartData} barCategoryGap="20%">
        <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--st1))" />
        <XAxis
          dataKey="name"
          tick={{ fill: 'hsl(var(--muted-foreground))', fontSize: 12 }}
          stroke="hsl(var(--st2))"
        />
        <YAxis
          tickFormatter={(v: number) => formatMs(v)}
          tick={{ fill: 'hsl(var(--muted-foreground))', fontSize: 12 }}
          stroke="hsl(var(--st2))"
        />
        <Tooltip content={<PercentilesTooltip />} cursor={{ fill: 'hsl(var(--muted) / 0.4)' }} />
        <Bar dataKey="avg" name="Avg" fill="hsl(var(--primary) / 0.4)" radius={[4, 4, 0, 0]} />
        <Bar dataKey="p95" name="P95" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} />
      </BarChart>
    </ChartCard>
  )
}

import { useMemo } from 'react'
import { Bar, BarChart, Legend, Tooltip, XAxis, YAxis } from 'recharts'
import { computeAvg, formatMs } from '@/lib/observability-format'
import type { SessionMetrics } from '@/lib/observability-types'
import { usePerformance } from '@/lib/observability-hooks'
import { ChartCard } from '@/components/observability-chart-shared'

const COLORS = {
  stt: 'hsl(210 80% 55%)',
  llm: 'hsl(270 60% 55%)',
  tts: 'hsl(150 60% 45%)',
  unaccounted: 'hsl(230 7% 78%)',
}

interface BreakdownRow {
  label: string
  stt: number
  llm: number
  tts: number
  unaccounted: number
  total: number
}

const PipelineTooltip = ({
  active,
  payload,
}: {
  active?: boolean
  payload?: Array<{ payload: BreakdownRow }>
}) => {
  if (!active || !payload?.length) return null
  const d = payload[0].payload
  return (
    <div className="rounded-lg border bg-background p-3 text-s-400 shadow-md">
      <p className="font-medium mb-1">{d.label}</p>
      <div className="grid grid-cols-2 gap-x-4 gap-y-0.5">
        <span style={{ color: COLORS.stt }}>STT</span>
        <span>{formatMs(d.stt)}</span>
        <span style={{ color: COLORS.llm }}>LLM</span>
        <span>{formatMs(d.llm)}</span>
        <span style={{ color: COLORS.tts }}>TTS</span>
        <span>{formatMs(d.tts)}</span>
        <span className="text-muted-foreground">Other</span>
        <span>{formatMs(d.unaccounted)}</span>
        <span className="font-medium">Total</span>
        <span className="font-medium">{formatMs(d.total)}</span>
      </div>
    </div>
  )
}

export const PipelineBreakdownChart = ({ metrics: metricsProp }: { metrics?: SessionMetrics | null }) => {
  const { metrics: hookMetrics } = usePerformance()
  const metrics = metricsProp ?? hookMetrics

  const chartData = useMemo(() => {
    if (!metrics?.turns?.length) return []

    const sttValues = metrics.turns.map((t) => t.stt_delay_ms).filter((v): v is number => v != null)
    const llmValues = metrics.turns.map((t) => t.llm_ttft_ms).filter((v): v is number => v != null)
    const ttsValues = metrics.turns.map((t) => t.tts_ttfb_ms).filter((v): v is number => v != null)
    const totalValues = metrics.turns
      .map((t) => t.user_perceived_ms)
      .filter((v): v is number => v != null)

    if (!totalValues.length) return []

    const total = computeAvg(totalValues)
    const stt = computeAvg(sttValues)
    const llm = computeAvg(llmValues)
    const tts = computeAvg(ttsValues)
    const unaccounted = Math.max(0, total - stt - llm - tts)

    return [{ label: 'Avg', stt, llm, tts, unaccounted, total }]
  }, [metrics])

  if (!chartData.length) return null

  return (
    <ChartCard
      title="Pipeline Breakdown"
      subtitle="Where is time spent in the pipeline?"
      legend={[]}
      chartHeight="h-48"
    >
      <BarChart data={chartData} layout="vertical" barCategoryGap="30%">
        <XAxis
          type="number"
          tickFormatter={(v: number) => formatMs(v)}
          tick={{ fill: 'hsl(var(--muted-foreground))', fontSize: 12 }}
          stroke="hsl(var(--st2))"
        />
        <YAxis
          type="category"
          dataKey="label"
          tick={{ fill: 'hsl(var(--muted-foreground))', fontSize: 12 }}
          stroke="hsl(var(--st2))"
          width={40}
        />
        <Tooltip content={<PipelineTooltip />} cursor={{ fill: 'hsl(var(--muted) / 0.4)' }} />
        <Legend formatter={(value: string) => <span className="text-xs">{value}</span>} />
        <Bar dataKey="stt" name="STT" stackId="stack" fill={COLORS.stt} radius={[0, 0, 0, 0]} />
        <Bar dataKey="llm" name="LLM" stackId="stack" fill={COLORS.llm} />
        <Bar dataKey="tts" name="TTS" stackId="stack" fill={COLORS.tts} />
        <Bar
          dataKey="unaccounted"
          name="Other"
          stackId="stack"
          fill={COLORS.unaccounted}
          radius={[0, 4, 4, 0]}
        />
      </BarChart>
    </ChartCard>
  )
}

import { useMemo } from 'react'
import { CartesianGrid, Line, LineChart, Tooltip, XAxis, YAxis } from 'recharts'
import { formatMs } from '@/lib/observability-format'
import type { SessionMetrics } from '@/lib/observability-types'
import { usePerformance } from '@/lib/observability-hooks'
import { ChartCard, ChartTooltipShell } from '@/components/observability-chart-shared'

interface ChartEntry {
  turn: number
  perceived?: number
  llm?: number
  tts?: number
}

const LatencyTooltip = ({
  active,
  payload,
  label,
}: {
  active?: boolean
  payload?: Array<{ name: string; value: number; color: string }>
  label?: number
}) => {
  return (
    <ChartTooltipShell
      active={active}
      label={label}
      rows={
        payload?.length
          ? payload.map((p) => ({ label: p.name, value: formatMs(p.value), color: p.color }))
          : []
      }
    />
  )
}

export const LatencyOverTurnsChart = ({ metrics: metricsProp }: { metrics?: SessionMetrics | null }) => {
  const { metrics: hookMetrics } = usePerformance()
  const metrics = metricsProp ?? hookMetrics

  const chartData = useMemo<ChartEntry[]>(() => {
    if (!metrics?.turns?.length) return []
    return metrics.turns
      .filter((t) => t.user_perceived_ms != null || t.llm_ttft_ms != null || t.tts_ttfb_ms != null)
      .map((t) => ({
        turn: t.turn_number,
        perceived: t.user_perceived_ms,
        llm: t.llm_ttft_ms,
        tts: t.tts_ttfb_ms,
      }))
  }, [metrics])

  if (!chartData.length) return null

  return (
    <ChartCard
      title="Latency Over Turns"
      subtitle="How latency changes throughout the conversation"
      legend={[
        { color: 'hsl(var(--primary))', label: 'User Perceived' },
        { color: 'hsl(270 60% 55%)', label: 'LLM TTFT' },
        { color: 'hsl(150 60% 45%)', label: 'TTS TTFB' },
      ]}
    >
      <LineChart data={chartData}>
        <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--st1))" />
        <XAxis
          dataKey="turn"
          tick={{ fill: 'hsl(var(--muted-foreground))', fontSize: 12 }}
          stroke="hsl(var(--st2))"
        />
        <YAxis
          tickFormatter={(v: number) => formatMs(v)}
          tick={{ fill: 'hsl(var(--muted-foreground))', fontSize: 12 }}
          stroke="hsl(var(--st2))"
        />
        <Tooltip content={<LatencyTooltip />} />
        <Line type="monotone" dataKey="perceived" name="User Perceived" stroke="hsl(var(--primary))" dot={false} strokeWidth={2} connectNulls />
        <Line type="monotone" dataKey="llm" name="LLM TTFT" stroke="hsl(270 60% 55%)" dot={false} strokeWidth={2} connectNulls />
        <Line type="monotone" dataKey="tts" name="TTS TTFB" stroke="hsl(150 60% 45%)" dot={false} strokeWidth={2} connectNulls />
      </LineChart>
    </ChartCard>
  )
}

import { useEffect, useRef } from 'react'
import { Badge } from '@/components/ui/badge'
import { Bot, Code2, MessageSquare, User, Zap } from 'lucide-react'
import { formatMs } from '@/lib/observability-format'
import type { ChatItem, SessionMetrics, TurnRecord } from '@/lib/observability-types'
import { useTranscript } from '@/lib/observability-hooks'

const LatencyPill = ({ label, ms }: { label: string; ms: number | undefined }) => {
  if (ms == null) return null
  const color =
    ms < 200
      ? 'text-green-600 bg-green-500/10'
      : ms < 500
        ? 'text-yellow-600 bg-yellow-500/10'
        : 'text-red-500 bg-red-500/10'
  return (
    <span
      title={`${label}: ${formatMs(ms)}`}
      className={`inline-flex items-center rounded px-1.5 py-0.5 text-[10px] font-mono tabular-nums ${color}`}
    >
      {label}&nbsp;&nbsp;|&nbsp;&nbsp;{formatMs(ms)}
    </span>
  )
}

